import os
from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismListProjectsNode(BaseNode):
    name = "Prism: List Projects"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_output("projects", "list")
        self.add_output("count", "int")

    def _scan_root_for_projects(self, core, pm, root_dir, pipeline_folder, seen, out):
        if not root_dir or not os.path.isdir(root_dir):
            return
        try:
            for entry in os.scandir(root_dir):
                if not entry.is_dir():
                    continue
                cfg = os.path.join(entry.path, pipeline_folder, 'pipeline.json')
                if not os.path.exists(cfg) or cfg in seen:
                    continue
                seen.add(cfg)
                name = entry.name
                try:
                    n = core.getConfig('globals', 'project_name', configPath=cfg)
                    if n:
                        name = n
                except Exception:
                    pass
                out.append({'configPath': cfg, 'name': name, 'source': 'disk'})
        except PermissionError:
            pass

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        if core is None:
            self.log_error("No PrismCore found. Add a prism_core_init node to your graph.")
            return {'projects': [], 'count': 0}
        try:
            pm = getattr(core, 'projects', None)

            # Prism-reported projects (recent + configured paths)
            known = []
            if pm is not None:
                for method in ('getAvailableProjects', 'getRecentProjects'):
                    fn = getattr(pm, method, None)
                    if callable(fn):
                        try:
                            result = fn()
                            if result:
                                known = list(result)
                                break
                        except Exception:
                            pass

            # Pipeline subfolder name (usually '00_Pipeline')
            pipeline_folder = '00_Pipeline'
            if pm is not None:
                try:
                    pf = getattr(pm, 'getDefaultPipelineFolder', None)
                    if callable(pf):
                        pipeline_folder = pf() or pipeline_folder
                except Exception:
                    pass

            # Build a deduplicated result starting from known projects
            seen = set()
            projects = []
            for p in known:
                cfg = p.get('configPath', '')
                if cfg:
                    seen.add(cfg)
                projects.append(p)

            # Collect root dirs to scan from known projects + getDefaultLocalPath
            root_dirs = set()
            for p in known:
                cfg = p.get('configPath', '')
                if cfg:
                    # cfg = <root>/<ProjectName>/<pipeline_folder>/pipeline.json
                    root_dirs.add(os.path.dirname(os.path.dirname(os.path.dirname(cfg))))
            if pm is not None:
                for method in ('getDefaultLocalPath',):
                    fn = getattr(pm, method, None)
                    if callable(fn):
                        try:
                            path = fn()
                            if path and os.path.isdir(path):
                                root_dirs.add(path)
                        except Exception:
                            pass

            # Scan each root dir for unlisted projects
            for root in root_dirs:
                self._scan_root_for_projects(core, pm, root, pipeline_folder, seen, projects)

            self.log_info(f"Found {len(projects)} project(s)")
            return {'projects': projects, 'count': len(projects)}
        except Exception as e:
            self.log_error(f"list_projects failed: {e}")
            return {'projects': [], 'count': 0}

def register_node():
    return PrismListProjectsNode
